using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // HasIndex removed: Cosmos DB indexing is managed via the container's
        // indexing policy (Azure Portal / Bicep / Terraform), not EF Core.
        // In EF Core 9 HasIndex throws InvalidOperationException for Cosmos entities.

        modelBuilder.Entity<Blog>(b =>
        {
            // Preserve the EF Core 8 discriminator property name ("Discriminator")
            // instead of the new default ("$type").
            b.HasDiscriminator<string>("Discriminator");

            // Preserve the EF Core 8 compound id format ("Blog|1")
            // instead of the new key-only format ("1").
            b.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

